ee:message.ee:set-payload:
%dw 2.0
output application/json
var cid = attributes.headers.'x-correlation-id' default correlationId default uuid()
---
{
  status: {
    code: "ERROR",
    httpStatus: vars.httpStatus default 500,
    message: "Snowflake System API request failed"
  },
  meta: {
    correlationId: cid,
    interfaceId: "PAY-001",
    dateTimeStamp: now(),
    originatingSystem: "MuleSoft",
    targetSystem: "Snowflake",
    requestingAPI: attributes.requestPath default "pay001-snowflake-sys-api",
    responseAPIorSystem: "Snowflake",
    muleEnvironment: p('env')
  },
  error: {
    errorType: error.errorType as String default "UNKNOWN",
    errorMessage: error.description default error.detailedDescription default "Unhandled system error",
    additionalDetails: error.cause.message default null
  }
}
